if (! function_exists('tool_test_harness')) {
    function tool_test_harness($tools_path = null, $max_files = null, $verbose = null)
    {
        $tools_path = isset($tools_path) ? trim($tools_path) : 'storage/agent/tools';
        $max_files = isset($max_files) ? max(0, (int)$max_files) : 0;
        $verbose = isset($verbose) ? (bool)$verbose : true;

        // Resolve absolute path
        $base_dir = getcwd();
        $full_path = $base_dir . '/' . ltrim($tools_path, '/');

        if (!is_dir($full_path)) {
            return ['error' => "Tools directory not found: $tools_path", 'summary' => null, 'results' => []];
        }

        $files = scandir($full_path);
        $php_files = [];
        foreach ($files as $f) {
            if (pathinfo($f, PATHINFO_EXTENSION) === 'php' && $f !== '.gitignore') {
                $php_files[] = $f;
            }
        }
        sort($php_files);

        if ($max_files > 0) {
            $php_files = array_slice($php_files, 0, $max_files);
        }

        $results = [];
        $passed = 0;
        $failed = 0;
        $warnings = 0;

        foreach ($php_files as $file) {
            $filepath = $full_path . '/' . $file;
            $tool_name = pathinfo($file, PATHINFO_FILENAME);
            
            $result = [
                'file' => $file,
                'tool_name' => $tool_name,
                'lint_status' => 'unknown',
                'lint_output' => '',
                'function_exists' => false,
                'has_definition' => false,
            ];
            
            // 1. Syntax check via php -l
            $cmd = escapeshellcmd('php') . ' -l ' . escapeshellarg($filepath) . ' 2>&1';
            $lint_output = trim(shell_exec($cmd));
            
            if ($lint_output === null) {
                $result['lint_status'] = 'error';
                $result['lint_output'] = 'Failed to run php -l (shell_exec disabled?)';
                $failed++;
            } elseif (str_starts_with($lint_output, 'No syntax errors')) {
                $result['lint_status'] = 'pass';
                $passed++;
            } else {
                $result['lint_status'] = 'fail';
                $result['lint_output'] = $lint_output;
                $failed++;
            }
            
            // 2. Check that the file has a $toolDefinition_ array
            $content = file_get_contents($filepath);
            $result['has_definition'] = str_contains($content, '$toolDefinition_');
            
            // 3. Check if function is declared (via function_exists check on the tool name)
            // We can't safely include all files in same process due to redefinition conflicts,
            // but we can check the source for the function definition pattern
            if (preg_match('/function\s+' . preg_quote($tool_name, '/') . '\s*\(/', $content)) {
                $result['function_exists'] = true;
            }
            
            $results[] = $result;
        }

        $summary = [
            'total' => count($php_files),
            'passed' => $passed,
            'failed' => $failed,
            'warnings' => $warnings,
            'all_pass' => ($failed === 0),
        ];

        // If not verbose, strip lint output from passing files
        if (!$verbose) {
            foreach ($results as &$r) {
                if ($r['lint_status'] === 'pass') {
                    $r['lint_output'] = '';
                }
            }
            unset($r);
        }

        return [
            'error' => null,
            'summary' => $summary,
            'results' => $results,
        ];
    }
